# Auto-generated for the Hugging Face Space: brand header, light-theme JS, and CSS
# extracted from the desktop app so the Space matches its look.

BRAND_HEADER_HTML = '\n<div id="medilens-header">\n  <img class="brand-logo" src="data:image/png;base64," alt="MediLens logo" />\n  <div class="brand-text">\n    <h2>MediLens</h2>\n    <p>Medicine label helper &nbsp;&middot;&nbsp; Local &nbsp;&middot;&nbsp; Powered by small AI models</p>\n  </div>\n</div>\n'

FORCE_LIGHT_THEME_JS = "\n() => {\n    const url = new URL(window.location);\n    if (url.searchParams.get('__theme') !== 'light') {\n        url.searchParams.set('__theme', 'light');\n        window.location.replace(url.href);\n    }\n}\n"

CUSTOM_CSS = '\ufeff/* â”€â”€ Force light palette (backstop if .dark class is applied) â”€â”€â”€â”€â”€ */\n.dark {\n    --body-background-fill: #f0f4f5;\n    --background-fill-primary: #ffffff;\n    --background-fill-secondary: #ffffff;\n    --block-background-fill: #ffffff;\n    --border-color-primary: #e3e8eb;\n    --body-text-color: #212b32;\n    --body-text-color-subdued: #425563;\n    --color-accent-soft: #e8f4fe;\n    color-scheme: light;\n}\nhtml { color-scheme: light; }\n\n/* â”€â”€ Base â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n.gradio-container {\n    background: #f0f4f5 !important;\n    font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif !important;\n}\n* {\n    font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif !important;\n}\n\n/* Force all input and textarea elements to white background with dark text */\ntextarea,\ninput[type="text"],\ninput[type="number"],\ninput[type="search"],\n.block textarea,\n.wrap textarea {\n    background: #ffffff !important;\n    color: #212b32 !important;\n    border-color: #aeb7bd !important;\n}\n\n/* â”€â”€ Brand header â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n/* Zero the HTML wrapper padding so the blue card spans the full content\n   width, matching the accordion below it. */\n#brand-header-block {\n    padding: 0 !important;\n    border: none !important;\n    background: transparent !important;\n}\n#medilens-header {\n    background: #005eb8;\n    border-radius: 24px;\n    padding: 24px 28px 20px;\n    margin-bottom: 12px;\n    box-shadow: 0 1px 3px rgba(0, 94, 184, 0.30), 0 6px 16px rgba(0, 94, 184, 0.18);\n    display: flex;\n    align-items: center;\n    gap: 16px;\n}\n#medilens-header .brand-logo {\n    height: 60px;\n    width: auto;\n    flex: 0 0 auto;\n}\n#medilens-header h2 {\n    color: white !important;\n    font-size: 1.75rem !important;\n    font-weight: 700 !important;\n    margin: 0 0 4px 0 !important;\n    letter-spacing: -0.01em !important;\n}\n#medilens-header p {\n    color: #aed6f1 !important;\n    margin: 0 !important;\n    font-size: 0.9rem !important;\n    line-height: 1.5 !important;\n}\n\n/* â”€â”€ Intro text (hide h1, style paragraph) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#intro-text .prose h1,\n#intro-text h1 {\n    display: none !important;\n}\n#intro-text {\n    background: #e8f4fe !important;\n    border-left: 4px solid #005eb8 !important;\n    padding: 12px 16px !important;\n    border-radius: 0 16px 16px 0 !important;\n    box-shadow: none !important;\n    margin-bottom: 4px !important;\n}\n#intro-text p {\n    color: #212b32 !important;\n    font-size: 0.9rem !important;\n    margin: 0 !important;\n    line-height: 1.6 !important;\n}\n\n/* â”€â”€ Top panels â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#top-left-panel,\n#top-right-panel {\n    background: white !important;\n    border-radius: 20px !important;\n    padding: 24px !important;\n    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06), 0 4px 12px rgba(0, 0, 0, 0.06) !important;\n    border: 1px solid #e3e8eb !important;\n    min-height: 480px;\n}\n\n/* â”€â”€ Image upload â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n/* Fixed-height image box so nothing shifts between empty and uploaded states */\n#medicine-image {\n    height: 250px !important;\n    min-height: 250px !important;\n    max-height: 250px !important;\n    border-radius: 16px;\n    border: 2px dashed #aeb7bd !important;\n    background: #f0f4f5;\n    position: relative !important;\n    overflow: hidden !important;\n}\n/* Pin the upload/webcam buttons at a fixed spot near the top; never moves */\n#medicine-image .source-selection {\n    position: absolute !important;\n    top: 6px !important;\n    left: 8px !important;\n    right: 8px !important;\n    z-index: 5 !important;\n    background: #f0f4f5 !important;\n    border-radius: 12px !important;\n    display: flex !important;\n    align-items: center !important;\n    justify-content: center !important;\n    height: 40px !important;\n    min-height: 40px !important;\n    max-height: 40px !important;\n    padding: 0 !important;\n    margin: 0 !important;\n    overflow: visible !important;\n    border: none !important;\n    border-bottom: none !important;\n    box-shadow: none !important;\n}\n#medicine-image .source-selection button {\n    margin: 0 6px !important;\n    opacity: 1 !important;\n    visibility: visible !important;\n    border: none !important;\n}\n/* Reserve space at the top so the photo sits below the buttons (does not cover them) */\n#medicine-image .image-container {\n    height: 250px !important;\n    padding-top: 52px !important;\n    box-sizing: border-box !important;\n}\n#medicine-image .image-frame,\n#medicine-image .image-preview,\n#medicine-image img {\n    max-height: 185px !important;\n    object-fit: contain !important;\n}\n\n/* â”€â”€ Match HTML card â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#match-output {\n    background: #e8f4fe;\n    border: 1px solid #aed6f1;\n    border-radius: 16px;\n    padding: 10px 16px;\n    min-height: 69px;\n    margin: 0 -3px 4px -3px;\n    width: calc(100% + 6px);\n    box-sizing: border-box;\n    display: flex;\n    flex-direction: column;\n    justify-content: center;\n}\n.match-card .match-medicine-name {\n    font-size: 1.05rem;\n    font-weight: 700;\n    color: #212b32;\n    margin: 0 0 5px 0;\n    line-height: 1.25;\n}\n.match-na {\n    color: #768692;\n    font-style: italic;\n    margin: 0;\n    padding: 6px 0;\n    font-size: 0.9rem;\n}\n.confidence-badge {\n    display: inline-flex;\n    align-items: center;\n    padding: 2px 10px;\n    border-radius: 9999px;\n    font-size: 0.68rem;\n    font-weight: 700;\n    letter-spacing: 0.01em;\n}\n.confidence-high   { background: #d4edda; color: #155724; border: 1px solid #b8dfc4; }\n.confidence-medium { background: #fff3cd; color: #7a5000; border: 1px solid #ffe69c; }\n.confidence-low    { background: #f8d7da; color: #6b1a22; border: 1px solid #f1b0b7; }\n\n/* â”€â”€ Explanation output (Medicine use) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#explanation-output textarea {\n    background: #eafaf0 !important;\n    border-color: #b7e0c4 !important;\n    color: #212b32 !important;\n    border-left: 4px solid #007f3b !important;\n    border-radius: 0 14px 14px 0 !important;\n    font-size: 0.9rem !important;\n    margin: 0 -4px !important;\n    width: calc(100% + 8px) !important;\n    box-sizing: border-box !important;\n}\n/* Green label pill to match the Medicine use box */\n#explanation-output label span {\n    background: #d4eddb !important;\n    color: #00451f !important;\n    padding: 2px 10px !important;\n    border-radius: 9999px !important;\n}\n\n/* â”€â”€ Warning output â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#warning-output textarea {\n    background: #fff9e6 !important;\n    border-color: #ffb81c !important;\n    color: #4a3700 !important;\n    border-left: 4px solid #ffb81c !important;\n    border-radius: 0 14px 14px 0 !important;\n    font-size: 0.9rem !important;\n    margin: 0 -4px !important;\n    width: calc(100% + 8px) !important;\n    box-sizing: border-box !important;\n}\n/* Amber label pill to match the Safety warning box */\n#warning-output label span {\n    background: #fff3cd !important;\n    color: #4a3700 !important;\n    padding: 2px 10px !important;\n    border-radius: 9999px !important;\n}\n\n/* â”€â”€ Source URL (HTML) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n/* Reserve fixed space so the right panel does not resize when the link appears */\n#source-url-output {\n    min-height: 64px;\n}\n.source-url-box {\n    background: #f0f4f5;\n    border: 1px solid #aeb7bd;\n    border-radius: 12px;\n    padding: 8px 10px;\n    font-size: 0.9rem;\n    color: #212b32;\n    margin: 0 -4px;\n    width: calc(100% + 8px);\n    box-sizing: border-box;\n}\n.source-url-label {\n    display: block;\n    font-size: 0.72rem;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.04em;\n    color: #768692;\n    margin-bottom: 4px;\n}\n.source-url-box a {\n    color: #005eb8;\n    text-decoration: underline;\n    font-weight: 600;\n    word-break: break-all;\n}\n.source-url-box a:hover { color: #003087; }\n\n/* â”€â”€ OCR textbox (compact) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#ocr-output textarea {\n    height: 200px !important;\n    min-height: 200px !important;\n    max-height: 200px !important;\n    overflow-y: auto !important;\n    background: #ffffff !important;\n    color: #212b32 !important;\n}\n\n/* â”€â”€ Read button (NHS green) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#read-btn button {\n    background: #007f3b !important;\n    border-radius: 9999px !important;\n    font-weight: 600 !important;\n    font-size: 1rem !important;\n    letter-spacing: 0.02em !important;\n    padding: 14px 24px !important;\n    border: none !important;\n    box-shadow: 0 1px 2px rgba(0, 64, 29, 0.30), 0 2px 6px rgba(0, 127, 59, 0.25) !important;\n    color: white !important;\n    width: 100% !important;\n    transition: background 0.15s ease, box-shadow 0.15s ease, transform 0.05s ease !important;\n}\n#read-btn button:hover {\n    background: #00662f !important;\n    box-shadow: 0 2px 4px rgba(0, 64, 29, 0.35), 0 6px 16px rgba(0, 127, 59, 0.30) !important;\n}\n#read-btn button:active {\n    transform: translateY(1px) !important;\n    box-shadow: 0 1px 2px rgba(0, 64, 29, 0.30) !important;\n}\n\n/* â”€â”€ Language selector â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#language-selector {\n    border: 2px solid #aeb7bd !important;\n    border-radius: 12px !important;\n    background: white !important;\n}\n\n/* â”€â”€ Manual label callout â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n/* No default group chrome (avoids a stray grey bar under the field) */\n#manual-label-section {\n    background: transparent !important;\n    border: none !important;\n    box-shadow: none !important;\n    padding: 0 !important;\n}\n/* Invisible flag: drives the field highlight via :has, shows no text/box */\n#manual-label-helper {\n    height: 0 !important;\n    min-height: 0 !important;\n    padding: 0 !important;\n    margin: 0 !important;\n    border: none !important;\n    background: transparent !important;\n    overflow: hidden !important;\n}\n#manual-label-section:has(#manual-label-helper:not([style*="display: none"])) {\n    border: 2px solid #ffb81c !important;\n    border-radius: 12px !important;\n    padding: 8px !important;\n    background: #fff9e6 !important;\n}\n#manual-label-section:has(#manual-label-helper:not([style*="display: none"])) #manual-label-input textarea {\n    border-color: #ffb81c !important;\n    box-shadow: 0 0 0 2px rgba(255, 184, 28, 0.3) !important;\n}\n\n/* â”€â”€ Model note text â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#model-note {\n    background: #eef6fd !important;\n    border-left: 4px solid #aed6f1 !important;\n    padding: 12px 16px !important;\n    border-radius: 0 16px 16px 0 !important;\n    margin-top: 4px !important;\n}\n#model-note, #model-note p {\n    color: #425563 !important;\n    font-size: 0.85rem !important;\n    line-height: 1.6 !important;\n}\n\n/* â”€â”€ Glossary note â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#glossary-note {\n    border-left: 4px solid #005eb8;\n    padding: 8px 12px;\n    background: #e8f4fe;\n    border-radius: 0 14px 14px 0;\n    color: #212b32 !important;\n}\n#glossary-note p { color: #212b32 !important; }\n\n/* â”€â”€ Progress â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n/* Fixed height so the left panel never grows when "Processing image..." appears */\n#processing-progress {\n    height: 20px !important;\n    min-height: 20px !important;\n    margin: 2px 0 0 0 !important;\n    overflow: hidden;\n}\n#read-action-section { gap: 2px !important; }\n#read-action-section > .form,\n#read-action-section .block {\n    margin-top: 0 !important;\n    margin-bottom: 0 !important;\n}\n.single-progress-status {\n    font-size: 12px;\n    line-height: 18px;\n    color: #425563;\n}\n\n/* â”€â”€ Technical panels â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n#technical-left-panel,\n#technical-right-panel {\n    min-height: 485px;\n    height: 100%;\n    box-sizing: border-box;\n}\n#server-status-output textarea {\n    min-height: 58px !important;\n    height: 58px !important;\n}\n#reachy-status-output textarea {\n    min-height: 112px !important;\n    height: 112px !important;\n}\n#use-vision-ocr-checkbox {\n    margin-bottom: -8px !important;\n}\n#start-servers-btn button {\n    min-height: 48px !important;\n    height: 48px !important;\n    border-radius: 9999px !important;\n    background: #d8e8f6 !important;\n    border: 1px solid #8ab8df !important;\n    color: #003087 !important;\n    font-weight: 700 !important;\n    box-shadow: 0 1px 2px rgba(0, 48, 135, 0.16), 0 2px 6px rgba(0, 94, 184, 0.12) !important;\n}\n#start-servers-btn button:hover {\n    background: #c7ddf1 !important;\n    border-color: #6da6d6 !important;\n}\n\n/* â”€â”€ Phone optimization â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€ */\n@media (max-width: 600px) {\n    #medilens-header {\n        border-radius: 16px;\n        padding: 16px 18px;\n        gap: 12px;\n    }\n    #medilens-header .brand-logo { height: 44px; }\n    #medilens-header h2 { font-size: 1.4rem !important; }\n    #medilens-header p { font-size: 0.8rem !important; }\n    #intro-text { padding: 10px 12px !important; }\n    #intro-text p { font-size: 0.85rem !important; }\n    #top-left-panel,\n    #top-right-panel {\n        padding: 16px !important;\n        min-height: 0 !important;\n        border-radius: 16px !important;\n    }\n    #medicine-image,\n    #medicine-image .image-container {\n        height: 210px !important;\n        min-height: 210px !important;\n        max-height: 210px !important;\n    }\n    #medicine-image .image-frame,\n    #medicine-image .image-preview,\n    #medicine-image img { max-height: 150px !important; }\n    #technical-left-panel,\n    #technical-right-panel { min-height: 0 !important; }\n    #model-note, #model-note p { font-size: 0.8rem !important; }\n}\n'
